+        "InfoLevel" => Some(Level::Info),
+        "WarnLevel" => Some(Level::Warn),
+        "ErrorLevel" => Some(Level::Error),
+        "FatalLevel" => Some(Level::Fatal),
+        _ => None,
+    }
