+                Ok(()) => {
+                    passed += 1;
+                    println!("  PASS: {}", name);
+                }
+                Err(msg) if msg.starts_with("SKIPPED:") => {
+                    skipped += 1;
+                    println!("  SKIP: {} - {}", name, msg);
+                }
+                Err(msg) => {
+                    failed += 1;
